+/// Convert various types to f64 for attribute return
+fn convertToF64(val: anytype) f64 {
+    const V = @TypeOf(val);
+    const vinfo = @typeInfo(V);
+    if (vinfo == .int or vinfo == .comptime_int) {
+        return @floatFromInt(val);
+    }
