+            // Compound statements might contain nested context managers that need blocks
+            .if_stmt, .for_stmt, .while_stmt, .try_stmt, .match_stmt => return false,
+            // Other statements like assign are fine
+            else => {},
+        }
+    }
+    return has_expr;
+}
